from typing import List

class Solution:
    def minOperations(self, nums: List[int], target: int) -> int:
        # Count the frequency of each power of two in nums
        count = [0] * 32
        for num in nums:
            for i in range(32):
                if num == (1 << i):
                    count[i] += 1
                    break

        # Convert target to binary and count the required powers of two
        required = [0] * 32
        for i in range(32):
            if (target >> i) & 1:
                required[i] = 1

        operations = 0
        for i in range(32):
            # If we need this power of two, check if we have it
            if required[i]:
                if count[i] > 0:
                    count[i] -= 1
                else:
                    # We need to split a higher power
                    # Find the next higher power that we have
                    j = i + 1
                    while j < 32 and count[j] == 0:
                        j += 1
                    if j == 32:
                        return -1
                    # Split the higher power into two lower ones
                    count[j] -= 1
                    count[j - 1] += 2
                    operations += (j - i)
                    # Now we have the required power, use it
                    count[j - 1] -= 1
            # If we have extra of this power, carry it to the next higher power
            if count[i] >= 2:
                count[i + 1] += count[i] // 2
                count[i] %= 2

        return operations
